142	// Return the "basic" type for an array item.
143	std::string basic_cell_type(const std::string celltype, int pos[3] = nullptr) {
144		std::string basicType = celltype;
145		if (celltype.compare(0, strlen("$array:"), "$array:") == 0) {
146			int pos_idx = celltype.find_first_of(':');
147			int pos_num = celltype.find_first_of(':', pos_idx + 1);
148			int pos_type = celltype.find_first_of(':', pos_num + 1);
149			basicType = celltype.substr(pos_type + 1);
150			if (pos != nullptr) {
151				pos[0] = pos_idx;
152				pos[1] = pos_num;
153				pos[2] = pos_type;
154			}
155		}
156		return basicType;
157	}
158	
159	// Try to read an IdString as a numbered connection name ("$123" or similar),
160	// writing the result to dst. If the string isn't of the right format, ignore
161	// dst and return false.
162	bool read_id_num(RTLIL::IdString str, int *dst)
163	{
164		log_assert(dst);
165	
166		const char *c_str = str.c_str();
167		if (c_str[0] != '$' || !('0' <= c_str[1] && c_str[1] <= '9'))
168			return false;
169	
170		*dst = atoi(c_str + 1);
171		return true;
172	}
173	
174	// A helper struct for expanding a module's interface connections in expand_module
175	struct IFExpander
176	{
177		IFExpander (RTLIL::Design &design, RTLIL::Module &m)
178			: module(m), has_interfaces_not_found(false)
179		{
180			// Keep track of all derived interfaces available in the current
181			// module in 'interfaces_in_module':
182			for (auto cell : module.cells()) {
183				if(!cell->get_bool_attribute(ID::is_interface))
184					continue;
185	
186				interfaces_in_module[cell->name] = design.module(cell->type);
187			}
188		}
189	
190		RTLIL::Module                          &module;
191		dict<RTLIL::IdString, RTLIL::Module*>   interfaces_in_module;
192	
193		bool                                    has_interfaces_not_found;
194		std::vector<RTLIL::IdString>            connections_to_remove;
195		std::vector<RTLIL::IdString>            connections_to_add_name;
196		std::vector<RTLIL::SigSpec>             connections_to_add_signal;
197		dict<RTLIL::IdString, RTLIL::Module*>   interfaces_to_add_to_submodule;
198		dict<RTLIL::IdString, RTLIL::IdString>  modports_used_in_submodule;
199	
200		// Reset the per-cell state
201		void start_cell()
202		{
203			has_interfaces_not_found = false;
204			connections_to_remove.clear();
205			connections_to_add_name.clear();
206			connections_to_add_signal.clear();
207			interfaces_to_add_to_submodule.clear();
208			modports_used_in_submodule.clear();
209		}
210	
211		// Set has_interfaces_not_found if there are pending interfaces that
212		// haven't been found yet (and might be found in the future). Print a
213		// warning if we've already gone over all the cells in the module.
214		void on_missing_interface(RTLIL::IdString interface_name)
215		{
216			// If there are cells that haven't yet been processed, maybe
217			// we'll find this interface in the future.
218			if (module.get_bool_attribute(ID::cells_not_processed)) {
219				has_interfaces_not_found = true;
220				return;
221			}
222	
223			// Otherwise, we have already gone over all cells in this
224			// module and the interface has still not been found. Warn
225			// about it and don't set has_interfaces_not_found (to avoid a
226			// loop).
227			log_warning("Could not find interface instance for `%s' in `%s'\n",
228				    interface_name.unescape(), &module);
229		}
230	
231		// Handle an interface connection from the module
232		void on_interface(RTLIL::Module        &submodule,
233		                  RTLIL::IdString       conn_name,
234		                  const RTLIL::SigSpec &conn_signals)
235		{
236			// Check if the connected wire is a potential interface in the parent module
237			std::string interface_name_str = conn_signals[0].wire->name.str();
238			// Strip the prefix '$dummywireforinterface' from the dummy wire to get the name
239			interface_name_str.replace(0,23,"");
240			interface_name_str = "\\" + interface_name_str;
241			RTLIL::IdString interface_name = interface_name_str;
242	
243			// If 'interfaces' in the cell have not be been handled yet, we aren't
244			// ready to derive the sub-module either
245			if (!module.get_bool_attribute(ID::interfaces_replaced_in_module)) {
246				on_missing_interface(interface_name);
247				return;
248			}
249	
250			// Check if the interface instance is present in module. Interface
251			// instances may either have the plain name or the name appended with
252			// '_inst_from_top_dummy'. Check for both of them here
253			int nexactmatch = interfaces_in_module.count(interface_name) > 0;
254			std::string interface_name_str2 =  interface_name_str + "_inst_from_top_dummy";
255			RTLIL::IdString interface_name2 = interface_name_str2;
256			int nmatch2 = interfaces_in_module.count(interface_name2) > 0;
257	
258			// If we can't find either name, this is a missing interface.
259			if (! (nexactmatch || nmatch2)) {
260				on_missing_interface(interface_name);
261				return;
262			}
263	
264			if (nexactmatch != 0) // Choose the one with the plain name if it exists
265				interface_name2 = interface_name;
266	
267			RTLIL::Module *mod_replace_ports = interfaces_in_module.at(interface_name2);
268	
269			// Go over all wires in interface, and add replacements to lists.
270			for (auto mod_wire : mod_replace_ports->wires()) {
271				std::string signal_name1 = conn_name.str() + "." + mod_wire->name.unescape();
272				std::string signal_name2 = interface_name.str() + "." + mod_wire->name.unescape();
273				connections_to_add_name.push_back(RTLIL::IdString(signal_name1));
274				if(module.wire(signal_name2) == nullptr) {
275					log_error("Could not find signal '%s' in '%s'\n",
276						  signal_name2.c_str(), module.name.unescape());
277				}
278				else {
279					RTLIL::Wire *wire_in_parent = module.wire(signal_name2);
280					connections_to_add_signal.push_back(wire_in_parent);
281				}
282			}
283			connections_to_remove.push_back(conn_name);
284			interfaces_to_add_to_submodule[conn_name] = interfaces_in_module.at(interface_name2);
285	
286			// Find if the sub-module has set a modport for the current interface
287			// connection. Add any modports to a dict which will be passed to
288			// AstModule::derive
289			string modport_name = submodule.wire(conn_name)->get_string_attribute(ID::interface_modport);
290			if (!modport_name.empty()) {
291				modports_used_in_submodule[conn_name] = "\\" + modport_name;
292			}
293		}
294	
295		// Handle a single connection from the module, making a note to expand
296		// it if it's an interface connection.
297		void on_connection(RTLIL::Module        &submodule,
298		                   RTLIL::IdString       conn_name,
299		                   const RTLIL::SigSpec &conn_signals)
300		{
301			// Does the connection look like an interface
302			if (
303				conn_signals.size() != 1 ||
304				conn_signals[0].wire == nullptr ||
305				conn_signals[0].wire->get_bool_attribute(ID::is_interface) == false ||
306				conn_signals[0].wire->name.str().find("$dummywireforinterface") != 0
307			)
308				return;
309	
310			// Check if the connection is present as an interface in the sub-module's port list
311			int id;
312			if (read_id_num(conn_name, &id)) {
313				/* Interface expansion is incompatible with positional arguments
314				 * during expansion, the port list gets each interface signal
315				 * inserted after the interface itself which means that the argument
316				 * positions in the parent module no longer match.
317				 *
318				 * Supporting this would require expanding the interfaces in the
319				 * parent module, renumbering the arguments to match, and then
320				 * iterating over the ports list to find the matching interface
321				 * (refactoring on_interface to accept different conn_names on the
322				 * parent and child).
323				 */
324				log_error("Unable to connect `%s' to submodule `%s' with positional interface argument `%s'!\n",
325					module.name,
326					submodule.name,
327					conn_signals[0].wire->name.str().substr(23)
328				);
329			} else {
330				// Lookup connection by name
331				const RTLIL::Wire *wire = submodule.wire(conn_name);
332				if (!wire || !wire->get_bool_attribute(ID::is_interface))
333					return;
334				}
335			// If the connection looks like an interface, handle it.
336			on_interface(submodule, conn_name, conn_signals);
337		}
338	
339		// Iterate over the connections in a cell, tracking any interface
340		// connections
341		void visit_connections(const RTLIL::Cell &cell,
342				       RTLIL::Module     &submodule)
343		{
344			for (const auto &conn : cell.connections()) {
345				on_connection(submodule, conn.first, conn.second);
346			}
347		}
348	
349		// Add/remove connections to the cell as necessary, replacing any SV
350		// interface port connection with the individual signal connections.
351		void rewrite_interface_connections(RTLIL::Cell &cell) const
352		{
353			for(unsigned int i=0;i<connections_to_add_name.size();i++) {
354				cell.connections_[connections_to_add_name[i]] = connections_to_add_signal[i];
355			}
356			// Remove the connection for the interface itself:
357			for(unsigned int i=0;i<connections_to_remove.size();i++) {
358				cell.connections_.erase(connections_to_remove[i]);
359			}
360		}
361	};
362	
363	// Get a module needed by a cell, either by deriving an abstract module or by
364	// loading one from a directory in libdirs.
365	//
366	// If the module can't be found and check is true then exit with an error
367	// message. Otherwise, return a pointer to the module if we derived or loaded
368	// something. or null otherwise (the module should be blackbox or we couldn't
369	// find it and check is not set).
370	RTLIL::Module *get_module(RTLIL::Design                  &design,
371	                          RTLIL::Cell                    &cell,
372	                          RTLIL::Module                  &parent,
373	                          bool                            check,
374	                          const std::vector<std::string> &libdirs)
375	{
376		std::string cell_type = cell.type.str();
377		RTLIL::Module *abs_mod = design.module("$abstract" + cell_type);
378		if (abs_mod) {
379			cell.type = abs_mod->derive(&design, cell.parameters);
380			cell.parameters.clear();
381			RTLIL::Module *mod = design.module(cell.type);
382			log_assert(mod);
383			return mod;
384		}
385	
386		// If the cell type starts with '$' and isn't '$abstract', we should
387		// treat it as a black box and skip.
388		if (cell_type[0] == '$')
389			return nullptr;
390	
391		for (auto &dir : libdirs) {
392			static const vector<pair<string, string>> extensions_list =
393				{
394				 {".v", "verilog"},
395				 {".sv", "verilog -sv"},
396				 {".il", "rtlil"}
397				};
398	
399			for (auto &ext : extensions_list) {
400				std::string filename = dir + "/" + cell.type.unescape() + ext.first;
401				if (!check_file_exists(filename))
402					continue;
403	
404				Frontend::frontend_call(&design, NULL, filename, ext.second);
405				RTLIL::Module *mod = design.module(cell.type);
406				if (!mod)
407					log_error("File `%s' from libdir does not declare module `%s'.\n",
408					          filename.c_str(), cell_type.c_str());
409				return mod;
410			}
411		}
412	
413		// We couldn't find the module anywhere. Complain if check is set.
414		if (check)
415			log_error("Module `%s' referenced in module `%s' in cell `%s' is not part of the design.\n",
416			          cell_type.c_str(), parent.name.c_str(), cell.name.c_str());
417	
418		return nullptr;
419	}
420	
421	// Check that the connections on the cell match those that are defined
422	// on the type: each named connection should match the name of a port
423	// and each positional connection should have an index smaller than
424	// the number of ports.
425	//
426	// Also do the same checks on the specified parameters.
427	void check_cell_connections(const RTLIL::Module &module, RTLIL::Cell &cell, RTLIL::Module &mod)
428	{
429		int id;
430		for (auto &conn : cell.connections()) {
431			if (read_id_num(conn.first, &id)) {
432				if (id <= 0 || id > GetSize(mod.ports))
433					log_error("Module `%s' referenced in module `%s' in cell `%s' "
434					          "has only %d ports, requested port %d.\n",
435					          cell.type.unescape(), &module, &cell,
436					          GetSize(mod.ports), id);
437				continue;
438			}
439	
440			const RTLIL::Wire* wire = mod.wire(conn.first);
441			if (!wire || wire->port_id == 0) {
442				log_error("Module `%s' referenced in module `%s' in cell `%s' "
443				          "does not have a port named '%s'.\n",
444				          cell.type.unescape(), &module, &cell,
445				          conn.first.unescape());
446			}
447		}
448		for (auto &param : cell.parameters) {
449			if (read_id_num(param.first, &id)) {
450				if (id <= 0 || id > GetSize(mod.avail_parameters))
451					log_error("Module `%s' referenced in module `%s' in cell `%s' "
452					          "has only %d parameters, requested parameter %d.\n",
453					          cell.type.unescape(), &module, &cell,
454					          GetSize(mod.avail_parameters), id);
455				continue;
456			}
457	
458			if (mod.avail_parameters.count(param.first) == 0 &&
459			    param.first[0] != '$' &&
460			    strchr(param.first.c_str(), '.') == NULL) {
461				log_error("Module `%s' referenced in module `%s' in cell `%s' "
462				          "does not have a parameter named '%s'.\n",
463				          cell.type.unescape(), &module, &cell,
464				          param.first.unescape());
465			}
466		}
467	}
468	
469	bool expand_module(RTLIL::Design *design, RTLIL::Module *module, bool flag_check, bool flag_simcheck, bool flag_smtcheck,
470			   std::vector<std::string> &libdirs)
471	{
472		bool did_something = false;
473		std::map<RTLIL::Cell*, std::pair<int, int>> array_cells;
474		std::string filename;
475	
476		bool has_interface_ports = false;
477	
478		// If any of the ports are actually interface ports, we will always need to
479		// reprocess the module:
480		if(!module->get_bool_attribute(ID::interfaces_replaced_in_module)) {
481			for (auto wire : module->wires()) {
482				if ((wire->port_input || wire->port_output) && wire->get_bool_attribute(ID::is_interface))
483					has_interface_ports = true;
484			}
485		}
486	
487		IFExpander if_expander(*design, *module);
488	
489		for (auto cell : module->cells())
490		{
491			if_expander.start_cell();
492	
493			if (cell->type.begins_with("$array:")) {
494				int pos[3];
495				basic_cell_type(cell->type.str(), pos);
496				int pos_idx = pos[0];
497				int pos_num = pos[1];
498				int pos_type = pos[2];
499				int idx = atoi(cell->type.substr(pos_idx + 1, pos_num).c_str());
500				int num = atoi(cell->type.substr(pos_num + 1, pos_type).c_str());
501				array_cells[cell] = std::pair<int, int>(idx, num);
502				cell->type = cell->type.substr(pos_type + 1);
503			}
504	
505			RTLIL::Module *mod = design->module(cell->type);
506			if (!mod)
507			{
508				mod = get_module(*design, *cell, *module, flag_check || flag_simcheck || flag_smtcheck, libdirs);
509	
510				// If we still don't have a module, treat the cell as a black box and skip
511				// it. Otherwise, we either loaded or derived something so should set the
512				// did_something flag before returning (to ensure we come back and expand
513				// the thing we just loaded).
514				if (mod)
515					did_something = true;
516	
517				continue;
518			}
519	
520			log_assert(mod);
521	
522			// Go over all connections and check if any of them are SV
523			// interfaces.
524			if_expander.visit_connections(*cell, *mod);
525	
526			if (flag_check || flag_simcheck || flag_smtcheck)
527				check_cell_connections(*module, *cell, *mod);
528	
529			if (mod->get_blackbox_attribute()) {
530				if (flag_simcheck || (flag_smtcheck && !mod->get_bool_attribute(ID::smtlib2_module)))
531					log_error("Module `%s' referenced in module `%s' in cell `%s' is a blackbox/whitebox module.\n",
532							cell->type.c_str(), module->name.c_str(), cell->name.c_str());
533				continue;
534			}
535	
536			// If interface instances not yet found, skip cell for now, and say we did something, so that we will return back here:
537			if(if_expander.has_interfaces_not_found) {
538				did_something = true; // waiting for interfaces to be handled
539				continue;
540			}
541	
542			if_expander.rewrite_interface_connections(*cell);
543	
544			// If there are no overridden parameters AND not interfaces, then we can use the existing module instance as the type
545			// for the cell:
546			if (cell->parameters.size() == 0 &&
547			    (if_expander.interfaces_to_add_to_submodule.size() == 0 ||
548			     !(cell->get_bool_attribute(ID::module_not_derived)))) {
549				// If the cell being processed is an the interface instance itself, go down to "handle_interface_instance:",
550				// so that the signals of the interface are added to the parent module.
551				if (mod->get_bool_attribute(ID::is_interface)) {
552					goto handle_interface_instance;
553				}
554				continue;
555			}
556	
557			cell->type = mod->derive(design,
558						 cell->parameters,
559						 if_expander.interfaces_to_add_to_submodule,
560						 if_expander.modports_used_in_submodule);
561			cell->parameters.clear();
562			did_something = true;
563	
564			handle_interface_instance:
565	
566				// We add all the signals of the interface explicitly to the parent module. This is always needed when we encounter
567				// an interface instance:
568				if (mod->get_bool_attribute(ID::is_interface) && cell->get_bool_attribute(ID::module_not_derived)) {
569					cell->set_bool_attribute(ID::is_interface);
570					RTLIL::Module *derived_module = design->module(cell->type);
571					if_expander.interfaces_in_module[cell->name] = derived_module;
572					did_something = true;
573				}
574			// We clear 'module_not_derived' such that we will not rederive the cell again (needed when there are interfaces connected to the cell)
575			cell->attributes.erase(ID::module_not_derived);
576		}
577		// Clear the attribute 'cells_not_processed' such that it can be known that we
578		// have been through all cells at least once, and that we can know whether
579		// to flag an error because of interface instances not found:
580		module->attributes.erase(ID::cells_not_processed);
581	
582	
583		// If any interface instances or interface ports were found in the module, we need to rederive it completely:
584		if ((if_expander.interfaces_in_module.size() > 0 || has_interface_ports) && !module->get_bool_attribute(ID::interfaces_replaced_in_module)) {
585			module->expand_interfaces(design, if_expander.interfaces_in_module);
586			return did_something;
587		}
588	
589		// Now that modules have been derived, we may want to reprocess this
590		// module given the additional available context.
591		if (module->reprocess_if_necessary(design))
592			return true;
593	
594		for (auto &it : array_cells)
595		{
596			RTLIL::Cell *cell = it.first;
597			int idx = it.second.first, num = it.second.second;
598	
599			if (design->module(cell->type) == nullptr)
600				log_error("Array cell `%s.%s' of unknown type `%s'.\n", module, cell, cell->type.unescape());
601	
602			RTLIL::Module *mod = design->module(cell->type);
603	
604			for (auto &conn : cell->connections_) {
605				int conn_size = conn.second.size();
606				RTLIL::IdString portname = conn.first;
607				if (portname.begins_with("$")) {
608					int port_id = atoi(portname.substr(1).c_str());
609					for (auto wire : mod->wires())
610						if (wire->port_id == port_id) {
611							portname = wire->name;
612							break;
613						}
614				}
615				if (mod->wire(portname) == nullptr)
616					log_error("Array cell `%s.%s' connects to unknown port `%s'.\n", module, cell, conn.first.unescape());
617				int port_size = mod->wire(portname)->width;
618				if (conn_size == port_size || conn_size == 0)
619					continue;
620				if (conn_size != port_size*num)
621					log_error("Array cell `%s.%s' has invalid port vs. signal size for port `%s'.\n", module, cell, conn.first.unescape());
622				conn.second = conn.second.extract(port_size*idx, port_size);
623			}
624		}
625	
626		return did_something;
627	}
