629	void hierarchy_worker(RTLIL::Design *design, std::set<RTLIL::Module*, IdString::compare_ptr_by_name<Module>> &used, RTLIL::Module *mod, int indent)
630	{
631		if (used.count(mod) > 0)
632			return;
633	
634		if (indent == 0)
635			log("Top module:  %s\n", mod->name);
636		else if (!mod->get_blackbox_attribute())
637			log("Used module: %*s%s\n", indent, "", mod->name);
638		used.insert(mod);
639	
640		for (auto cell : mod->cells()) {
641			std::string celltype = cell->type.str();
642			if (celltype.compare(0, strlen("$array:"), "$array:") == 0)
643				celltype = basic_cell_type(celltype);
644			if (design->module(celltype))
645				hierarchy_worker(design, used, design->module(celltype), indent+4);
646		}
647	}
648	
649	void hierarchy_clean(RTLIL::Design *design, RTLIL::Module *top, bool purge_lib)
650	{
651		std::set<RTLIL::Module*, IdString::compare_ptr_by_name<Module>> used;
652		hierarchy_worker(design, used, top, 0);
653	
654		std::vector<RTLIL::Module*> del_modules;
655		for (auto mod : design->modules())
656			if (used.count(mod) == 0)
657				del_modules.push_back(mod);
658			else {
659				// Now all interface ports must have been exploded, and it is hence
660				// safe to delete all of the remaining dummy interface ports:
661				pool<RTLIL::Wire*> del_wires;
662				for(auto wire : mod->wires()) {
663					if ((wire->port_input || wire->port_output) && wire->get_bool_attribute(ID::is_interface)) {
664						del_wires.insert(wire);
665					}
666				}
667				if (del_wires.size() > 0) {
668					mod->remove(del_wires);
669					mod->fixup_ports();
670				}
671			}
672	
673		int del_counter = 0;
674		for (auto mod : del_modules) {
675			if (!purge_lib && mod->get_blackbox_attribute())
676				continue;
677			log("Removing unused module `%s'.\n", mod->name);
678			design->remove(mod);
679			del_counter++;
680		}
681	
682		log("Removed %d unused modules.\n", del_counter);
683	}
