685	bool set_keep_print(std::map<RTLIL::Module*, bool> &cache, RTLIL::Module *mod)
686	{
687		if (cache.count(mod) == 0)
688			for (auto c : mod->cells()) {
689				RTLIL::Module *m = mod->design->module(c->type);
690				if ((m != nullptr && set_keep_print(cache, m)) || c->type == ID($print))
691					return cache[mod] = true;
692			}
693		return cache[mod];
694	}
