696	bool set_keep_assert(std::map<RTLIL::Module*, bool> &cache, RTLIL::Module *mod)
697	{
698		if (cache.count(mod) == 0)
699			for (auto c : mod->cells()) {
700				RTLIL::Module *m = mod->design->module(c->type);
701				if ((m != nullptr && set_keep_assert(cache, m)) || c->type.in(ID($check), ID($assert), ID($assume), ID($live), ID($fair), ID($cover)))
702					return cache[mod] = true;
703			}
704		return cache[mod];
705	}
