707	int find_top_mod_score(Design *design, Module *module, dict<Module*, int> &db)
708	{
709		if (db.count(module) == 0) {
710			int score = 0;
711			db[module] = 0;
712			for (auto cell : module->cells()) {
713				std::string celltype = cell->type.str();
714				// Is this an array instance
715				if (celltype.compare(0, strlen("$array:"), "$array:") == 0)
716					celltype = basic_cell_type(celltype);
717				// Is this cell a module instance?
718				auto instModule = design->module(celltype);
719				// If there is no instance for this, issue a warning.
720				if (instModule != nullptr) {
721					score = max(score, find_top_mod_score(design, instModule, db) + 1);
722				}
723			}
724			db[module] = score;
725		}
726		return db.at(module);
727	}
