729	RTLIL::Module *check_if_top_has_changed(Design *design, Module *top_mod)
730	{
731		if(top_mod != NULL && top_mod->get_bool_attribute(ID::initial_top))
732			return top_mod;
733		else {
734			for (auto mod : design->modules()) {
735				if (mod->get_bool_attribute(ID::top)) {
736					return mod;
737				}
738			}
739		}
740		return NULL;
741	}
