743	// Find a matching wire for an implicit port connection; traversing generate block scope
744	RTLIL::Wire *find_implicit_port_wire(Module *module, Cell *cell, const std::string& port)
745	{
746		const std::string &cellname = cell->name.str();
747		size_t idx = cellname.size();
748		while ((idx = cellname.find_last_of('.', idx-1)) != std::string::npos) {
749			Wire *found = module->wire(cellname.substr(0, idx+1) + port.substr(1));
750			if (found != nullptr)
751				return found;
752		}
753		return module->wire(port);
754	}
