847		void execute(std::vector<std::string> args, RTLIL::Design *design) override
848		{
849			log_header(design, "Executing HIERARCHY pass (managing design hierarchy).\n");
850	
851			bool flag_check = false;
852			bool flag_simcheck = false;
853			bool flag_smtcheck = false;
854			bool purge_lib = false;
855			RTLIL::Module *top_mod = NULL;
856			std::string load_top_mod;
857			std::vector<std::string> libdirs;
858	
859			bool auto_top_mode = false;
860			bool generate_mode = false;
861			bool keep_positionals = false;
862			bool keep_portwidths = false;
863			bool nodefaults = false;
864			bool nokeep_prints = false;
865			bool nokeep_asserts = false;
866			std::vector<std::string> generate_cells;
867			std::vector<generate_port_decl_t> generate_ports;
868			std::map<std::string, std::string> parameters;
869	
870			size_t argidx;
871			for (argidx = 1; argidx < args.size(); argidx++)
872			{
873				if (args[argidx] == "-generate" && !flag_check && !flag_simcheck && !flag_smtcheck && !top_mod) {
874					generate_mode = true;
875					log("Entering generate mode.\n");
876					while (++argidx < args.size()) {
877						const char *p = args[argidx].c_str();
878						generate_port_decl_t decl;
879						if (p[0] == 'i' && p[1] == 'o')
880							decl.input = true, decl.output = true, p += 2;
881						else if (*p == 'i')
882							decl.input = true, decl.output = false, p++;
883						else if (*p == 'o')
884							decl.input = false, decl.output = true, p++;
885						else
886							goto is_celltype;
887						if (*p == '@') {
888							char *endptr;
889							decl.index = strtol(++p, &endptr, 10);
890							if (decl.index < 1)
891								goto is_celltype;
892							p = endptr;
893						} else
894							decl.index = 0;
895						if (*(p++) != ':')
896							goto is_celltype;
897						if (*p == 0)
898							goto is_celltype;
899						decl.portname = p;
900						log("Port declaration: %s", decl.input ? decl.output ? "inout" : "input" : "output");
901						if (decl.index >= 1)
902							log(" [at position %d]", decl.index);
903						log(" %s\n", decl.portname);
904						generate_ports.push_back(decl);
905						continue;
906					is_celltype:
907						log("Celltype: %s\n", args[argidx]);
908						generate_cells.push_back(RTLIL::unescape_id(args[argidx]));
909					}
910					continue;
911				}
912				if (args[argidx] == "-check") {
913					flag_check = true;
914					continue;
915				}
916				if (args[argidx] == "-simcheck") {
917					flag_simcheck = true;
918					continue;
919				}
920				if (args[argidx] == "-smtcheck") {
921					flag_smtcheck = true;
922					continue;
923				}
924				if (args[argidx] == "-purge_lib") {
925					purge_lib = true;
926					continue;
927				}
928				if (args[argidx] == "-keep_positionals") {
929					keep_positionals = true;
930					continue;
931				}
932				if (args[argidx] == "-keep_portwidths") {
933					keep_portwidths = true;
934					continue;
935				}
936				if (args[argidx] == "-nodefaults") {
937					nodefaults = true;
938					continue;
939				}
940				if (args[argidx] == "-nokeep_prints") {
941					nokeep_prints = true;
942					continue;
943				}
944				if (args[argidx] == "-nokeep_asserts") {
945					nokeep_asserts = true;
946					continue;
947				}
948				if (args[argidx] == "-libdir" && argidx+1 < args.size()) {
949					libdirs.push_back(args[++argidx]);
950					continue;
951				}
952				if (args[argidx] == "-top") {
953					if (++argidx >= args.size())
954						log_cmd_error("Option -top requires an additional argument!\n");
955					load_top_mod = args[argidx];
956					continue;
957				}
958				if (args[argidx] == "-auto-top") {
959					auto_top_mode = true;
960					continue;
961				}
962				if (args[argidx] == "-chparam"  && argidx+2 < args.size()) {
963					const std::string &key = args[++argidx];
964					const std::string &value = args[++argidx];
965					auto r = parameters.emplace(key, value);
966					if (!r.second) {
967						log_warning("-chparam %s already specified: overwriting.\n", key);
968						r.first->second = value;
969					}
970					continue;
971				}
972				break;
973			}
974			extra_args(args, argidx, design, false);
975	
976			if (!load_top_mod.empty())
977			{
978				IdString top_name = RTLIL::escape_id(load_top_mod);
979				IdString abstract_id = "$abstract" + RTLIL::escape_id(load_top_mod);
980				top_mod = design->module(top_name);
981	
982				dict<RTLIL::IdString, RTLIL::Const> top_parameters;
983				if ((top_mod == nullptr && design->module(abstract_id)) || top_mod != nullptr) {
984					for (auto &para : parameters) {
985						SigSpec sig_value;
986						if (!RTLIL::SigSpec::parse(sig_value, NULL, para.second))
987							log_cmd_error("Can't decode value '%s'!\n", para.second);
988						RTLIL::Const c = sig_value.as_const();
989						c.tag_bare_integer_const(para.second);
990						top_parameters[RTLIL::escape_id(para.first)] = c;
991					}
992				}
993	
994				if (top_mod == nullptr && design->module(abstract_id))
995					top_mod = design->module(design->module(abstract_id)->derive(design, top_parameters));
996				else if (top_mod != nullptr && !top_parameters.empty())
997					top_mod = design->module(top_mod->derive(design, top_parameters));
998	
999				if (top_mod != nullptr && top_mod->name != top_name) {
1000					Module *m = top_mod->clone();
1001					m->name = top_name;
1002					Module *old_mod = design->module(top_name);
1003					if (old_mod)
1004						design->remove(old_mod);
1005					design->add(m);
1006					top_mod = m;
1007				}
1008			}
1009	
1010			bool verific_mod = false;
1011	#ifdef YOSYS_ENABLE_VERIFIC
1012			verific_mod = verific_import_pending;
1013	#endif
1014	
1015			if (top_mod == nullptr && !load_top_mod.empty()) {
1016	#ifdef YOSYS_ENABLE_VERIFIC
1017				if (verific_import_pending) {
1018					load_top_mod = verific_import(design, parameters, load_top_mod);
1019					top_mod = design->module(RTLIL::escape_id(load_top_mod));
1020				}
1021	#endif
1022				if (top_mod == NULL)
1023					log_cmd_error("Module `%s' not found!\n", load_top_mod);
1024			} else {
1025	#ifdef YOSYS_ENABLE_VERIFIC
1026				if (verific_import_pending)
1027					verific_import(design, parameters);
1028	#endif
1029			}
1030	
1031			if (generate_mode) {
1032				generate(design, generate_cells, generate_ports);
1033				return;
1034			}
1035	
1036			log_push();
1037	
1038			if (top_mod == nullptr)
1039				for (auto mod : design->modules())
1040					if (mod->get_bool_attribute(ID::top)) {
1041						log("Attribute `top' found on module `%s'. Setting top module to %s.\n", mod, mod);
1042						top_mod = mod;
1043					}
1044	
1045			if (top_mod == nullptr)
1046			{
1047				std::vector<IdString> abstract_ids;
1048				for (auto module : design->modules())
1049					if (module->name.begins_with("$abstract"))
1050						abstract_ids.push_back(module->name);
1051				for (auto abstract_id : abstract_ids)
1052					design->module(abstract_id)->derive(design, {});
1053				for (auto abstract_id : abstract_ids)
1054					design->remove(design->module(abstract_id));
1055			}
1056	
1057			if (top_mod == nullptr && auto_top_mode) {
1058				log_header(design, "Finding top of design hierarchy..\n");
1059				dict<Module*, int> db;
1060				for (Module *mod : design->selected_modules()) {
1061					int score = find_top_mod_score(design, mod, db);
1062					log("root of %3d design levels: %-20s\n", score, mod);
1063					if (!top_mod || score > db[top_mod])
1064						top_mod = mod;
1065				}
1066				if (top_mod != nullptr)
1067					log("Automatically selected %s as design top module.\n", top_mod);
1068			}
1069	
1070			if (top_mod != nullptr && top_mod->name.begins_with("$abstract")) {
1071				IdString top_name = top_mod->name.substr(strlen("$abstract"));
1072	
1073				dict<RTLIL::IdString, RTLIL::Const> top_parameters;
1074				for (auto &para : parameters) {
1075					SigSpec sig_value;
1076					if (!RTLIL::SigSpec::parse(sig_value, NULL, para.second))
1077						log_cmd_error("Can't decode value '%s'!\n", para.second);
1078					RTLIL::Const c = sig_value.as_const();
1079					c.tag_bare_integer_const(para.second);
1080					top_parameters[RTLIL::escape_id(para.first)] = c;
1081				}
1082	
1083				top_mod = design->module(top_mod->derive(design, top_parameters));
1084	
1085				if (top_mod != nullptr && top_mod->name != top_name) {
1086					Module *m = top_mod->clone();
1087					m->name = top_name;
1088					Module *old_mod = design->module(top_name);
1089					if (old_mod)
1090						design->remove(old_mod);
1091					design->add(m);
1092					top_mod = m;
1093				}
1094			}
1095	
1096			if ((flag_simcheck || flag_smtcheck) && top_mod == nullptr)
1097				log_error("Design has no top module.\n");
1098	
1099			if (top_mod != NULL) {
1100				for (auto mod : design->modules())
1101					if (mod == top_mod)
1102						mod->attributes[ID::initial_top] = RTLIL::Const(1);
1103					else
1104						mod->attributes.erase(ID::initial_top);
1105			}
1106	
1107			bool did_something = true;
1108			while (did_something)
1109			{
1110				did_something = false;
1111	
1112				std::set<RTLIL::Module*, IdString::compare_ptr_by_name<Module>> used_modules;
1113				if (top_mod != NULL) {
1114					log_header(design, "Analyzing design hierarchy..\n");
1115					hierarchy_worker(design, used_modules, top_mod, 0);
1116				} else {
1117					for (auto mod : design->modules())
1118						used_modules.insert(mod);
1119				}
1120	
1121				for (auto module : used_modules) {
1122					if (expand_module(design, module, flag_check, flag_simcheck, flag_smtcheck, libdirs))
1123						did_something = true;
1124				}
1125	
1126	
1127				// The top module might have changed if interface instances have been detected in it:
1128				RTLIL::Module *tmp_top_mod = check_if_top_has_changed(design, top_mod);
1129				if (tmp_top_mod != NULL) {
1130					if (tmp_top_mod != top_mod){
1131						top_mod = tmp_top_mod;
1132						top_mod->attributes[ID::initial_top] = RTLIL::Const(1);
1133						did_something = true;
1134					}
1135				}
1136	
1137				// Delete modules marked as 'to_delete':
1138				std::vector<RTLIL::Module *> modules_to_delete;
1139				for(auto mod : design->modules()) {
1140					if (mod->get_bool_attribute(ID::to_delete)) {
1141						modules_to_delete.push_back(mod);
1142					}
1143				}
1144				for(size_t i=0; i<modules_to_delete.size(); i++) {
1145					design->remove(modules_to_delete[i]);
1146				}
1147			}
1148	
1149	
1150			if (top_mod != NULL) {
1151				log_header(design, "Analyzing design hierarchy..\n");
1152				hierarchy_clean(design, top_mod, purge_lib);
1153			}
1154	
1155			if (top_mod != NULL) {
1156				for (auto mod : design->modules()) {
1157					if (mod == top_mod)
1158						mod->attributes[ID::top] = RTLIL::Const(1);
1159					else
1160						mod->attributes.erase(ID::top);
1161					mod->attributes.erase(ID::initial_top);
1162				}
1163			}
1164	
1165			if (!nokeep_prints) {
1166				std::map<RTLIL::Module*, bool> cache;
1167				for (auto mod : design->modules())
1168					if (set_keep_print(cache, mod)) {
1169						log("Module %s directly or indirectly displays text -> setting \"keep\" attribute.\n", mod);
1170						mod->set_bool_attribute(ID::keep);
1171					}
1172			}
1173	
1174			if (!nokeep_asserts) {
1175				std::map<RTLIL::Module*, bool> cache;
1176				for (auto mod : design->modules())
1177					if (set_keep_assert(cache, mod)) {
1178						log("Module %s directly or indirectly contains formal properties -> setting \"keep\" attribute.\n", mod);
1179						mod->set_bool_attribute(ID::keep);
1180					}
1181			}
1182	
1183			if (flag_simcheck || flag_smtcheck) {
1184				for (auto mod : design->modules()) {
1185					for (auto cell : mod->cells()) {
1186						if (!cell->type.in(ID($check), ID($assert), ID($assume), ID($live), ID($fair), ID($cover)))
1187							continue;
1188						if (!cell->has_attribute(ID(unsupported_sva)))
1189							continue;
1190	
1191						auto src = cell->get_src_attribute();
1192	
1193						if (!src.empty())
1194							src += ": ";
1195	
1196						log_error("%sProperty `%s' in module `%s' uses unsupported SVA constructs. See frontend warnings for details, run `chformal -remove a:unsupported_sva' to ignore.\n",
1197							src, cell->name.unescape(), mod->name.unescape());
1198					}
1199				}
1200			}
1201	
1202			if (!keep_positionals)
1203			{
1204				std::set<RTLIL::Module*> pos_mods;
1205				std::map<std::pair<RTLIL::Module*,int>, RTLIL::IdString> pos_map;
1206				std::vector<std::pair<RTLIL::Module*,RTLIL::Cell*>> pos_work;
1207	
1208				for (auto mod : design->modules())
1209				for (auto cell : mod->cells()) {
1210					RTLIL::Module *cell_mod = design->module(cell->type);
1211					if (cell_mod == nullptr)
1212						continue;
1213					for (auto &conn : cell->connections())
1214						if (conn.first[0] == '$' && '0' <= conn.first[1] && conn.first[1] <= '9') {
1215							pos_mods.insert(design->module(cell->type));
1216							pos_work.push_back(std::pair<RTLIL::Module*,RTLIL::Cell*>(mod, cell));
1217							break;
1218						}
1219	
1220					pool<std::pair<IdString, IdString>> params_rename;
1221					for (const auto &p : cell->parameters) {
1222						int id;
1223						if (read_id_num(p.first, &id)) {
1224							if (id <= 0 || id > GetSize(cell_mod->avail_parameters)) {
1225								log("  Failed to map positional parameter %d of cell %s.%s (%s).\n",
1226										id, mod, cell, cell->type.unescape());
1227							} else {
1228								params_rename.insert(std::make_pair(p.first, cell_mod->avail_parameters[id - 1]));
1229							}
1230						}
1231					}
1232					for (const auto &p : params_rename) {
1233						cell->setParam(p.second, cell->getParam(p.first));
1234						cell->unsetParam(p.first);
1235					}
1236				}
1237	
1238				for (auto module : pos_mods)
1239				for (auto wire : module->wires()) {
1240					if (wire->port_id > 0)
1241						pos_map[std::pair<RTLIL::Module*,int>(module, wire->port_id)] = wire->name;
1242				}
1243	
1244				for (auto &work : pos_work) {
1245					RTLIL::Module *module = work.first;
1246					RTLIL::Cell *cell = work.second;
1247					log("Mapping positional arguments of cell %s.%s (%s).\n",
1248							module, cell, cell->type.unescape());
1249					dict<RTLIL::IdString, RTLIL::SigSpec> new_connections;
1250					for (auto &conn : cell->connections()) {
1251						int id;
1252						if (read_id_num(conn.first, &id)) {
1253							std::pair<RTLIL::Module*,int> key(design->module(cell->type), id);
1254							if (pos_map.count(key) == 0) {
1255								log("  Failed to map positional argument %d of cell %s.%s (%s).\n",
1256										id, module, cell, cell->type.unescape());
1257								new_connections[conn.first] = conn.second;
1258							} else
1259								new_connections[pos_map.at(key)] = conn.second;
1260						} else
1261							new_connections[conn.first] = conn.second;
1262					}
1263					cell->connections_ = new_connections;
1264				}
1265			}
1266	
1267			// Determine default values
1268			dict<IdString, dict<IdString, Const>> defaults_db;
1269			if (!nodefaults)
1270			{
1271				for (auto module : design->modules())
1272					for (auto wire : module->wires())
1273						if (wire->port_input && wire->attributes.count(ID::defaultvalue))
1274							defaults_db[module->name][wire->name] = wire->attributes.at(ID::defaultvalue);
1275			}
1276			// Process SV implicit wildcard port connections
1277			std::set<Module*> blackbox_derivatives;
1278			std::vector<Module*> design_modules = design->modules();
1279	
1280			for (auto module : design_modules)
1281			{
1282				for (auto cell : module->cells())
1283				{
1284					if (!cell->get_bool_attribute(ID::wildcard_port_conns))
1285						continue;
1286					Module *m = design->module(cell->type);
1287	
1288					if (m == nullptr)
1289						log_error("Cell %s.%s (%s) has implicit port connections but the module it instantiates is unknown.\n",
1290								module, cell, cell->type.unescape());
1291	
1292					// Need accurate port widths for error checking; so must derive blackboxes with dynamic port widths
1293					if (m->get_blackbox_attribute() && !cell->parameters.empty() && m->get_bool_attribute(ID::dynports)) {
1294						IdString new_m_name = m->derive(design, cell->parameters, true);
1295						if (new_m_name.empty())
1296							continue;
1297						if (new_m_name != m->name) {
1298							m = design->module(new_m_name);
1299							blackbox_derivatives.insert(m);
1300						}
1301					}
1302	
1303					auto old_connections = cell->connections();
1304					for (auto wire : m->wires()) {
1305						// Find ports of the module that aren't explicitly connected
1306						if (!wire->port_input && !wire->port_output)
1307							continue;
1308						if (old_connections.count(wire->name))
1309							continue;
1310						// Make sure a wire of correct name exists in the parent
1311						Wire* parent_wire = find_implicit_port_wire(module, cell, wire->name.str());
1312	
1313						// Missing wires are OK when a default value is set
1314						if (!nodefaults && parent_wire == nullptr && defaults_db.count(cell->type) && defaults_db.at(cell->type).count(wire->name))
1315							continue;
1316	
1317						if (parent_wire == nullptr)
1318							log_error("No matching wire for implicit port connection `%s' of cell %s.%s (%s).\n",
1319									wire, module, cell, cell->type.unescape());
1320						if (parent_wire->width != wire->width)
1321							log_error("Width mismatch between wire (%d bits) and port (%d bits) for implicit port connection `%s' of cell %s.%s (%s).\n",
1322									parent_wire->width, wire->width,
1323									wire, module, cell, cell->type.unescape());
1324						cell->setPort(wire->name, parent_wire);
1325					}
1326					cell->attributes.erase(ID::wildcard_port_conns);
1327				}
1328			}
1329	
1330			if (!nodefaults)
1331			{
1332				for (auto module : design->modules())
1333					for (auto cell : module->cells())
1334					{
1335						if (defaults_db.count(cell->type) == 0)
1336							continue;
1337	
1338						if (keep_positionals) {
1339							bool found_positionals = false;
1340							for (auto &conn : cell->connections())
1341								if (conn.first[0] == '$' && '0' <= conn.first[1] && conn.first[1] <= '9')
1342									found_positionals = true;
1343							if (found_positionals)
1344								continue;
1345						}
1346	
1347						for (auto &it : defaults_db.at(cell->type))
1348							if (!cell->hasPort(it.first))
1349								cell->setPort(it.first, it.second);
1350					}
1351			}
1352	
1353			for (auto module : design_modules)
1354			{
1355				pool<Wire*> wand_wor_index;
1356				dict<Wire*, SigSpec> wand_map, wor_map;
1357				vector<SigSig> new_connections;
1358	
1359				for (auto wire : module->wires())
1360				{
1361					if (wire->get_bool_attribute(ID::wand)) {
1362						wand_map[wire] = SigSpec();
1363						wand_wor_index.insert(wire);
1364					}
1365					if (wire->get_bool_attribute(ID::wor)) {
1366						wor_map[wire] = SigSpec();
1367						wand_wor_index.insert(wire);
1368					}
1369				}
1370	
1371				for (auto &conn : module->connections())
1372				{
1373					SigSig new_conn;
1374					int cursor = 0;
1375	
1376					for (auto c : conn.first.chunks())
1377					{
1378						Wire *w = c.wire;
1379						SigSpec rhs = conn.second.extract(cursor, GetSize(c));
1380	
1381						if (wand_wor_index.count(w) == 0) {
1382							new_conn.first.append(c);
1383							new_conn.second.append(rhs);
1384						} else {
1385							if (wand_map.count(w)) {
1386								SigSpec sig = SigSpec(State::S1, GetSize(w));
1387								sig.replace(c.offset, rhs);
1388								wand_map.at(w).append(sig);
1389							} else {
1390								SigSpec sig = SigSpec(State::S0, GetSize(w));
1391								sig.replace(c.offset, rhs);
1392								wor_map.at(w).append(sig);
1393							}
1394						}
1395						cursor += GetSize(c);
1396					}
1397					new_connections.push_back(new_conn);
1398				}
1399				module->new_connections(new_connections);
1400	
1401				for (auto cell : module->cells())
1402				{
1403					if (!cell->known())
1404						continue;
1405	
1406					for (auto &conn : cell->connections())
1407					{
1408						if (!cell->output(conn.first))
1409							continue;
1410	
1411						SigSpec new_sig;
1412						bool update_port = false;
1413	
1414						for (auto c : conn.second.chunks())
1415						{
1416							Wire *w = c.wire;
1417	
1418							if (wand_wor_index.count(w) == 0) {
1419								new_sig.append(c);
1420								continue;
1421							}
1422	
1423							Wire *t = module->addWire(NEW_ID, GetSize(c));
1424							new_sig.append(t);
1425							update_port = true;
1426	
1427							if (wand_map.count(w)) {
1428								SigSpec sig = SigSpec(State::S1, GetSize(w));
1429								sig.replace(c.offset, t);
1430								wand_map.at(w).append(sig);
1431							} else {
1432								SigSpec sig = SigSpec(State::S0, GetSize(w));
1433								sig.replace(c.offset, t);
1434								wor_map.at(w).append(sig);
1435							}
1436						}
1437	
1438						if (update_port)
1439							cell->setPort(conn.first, new_sig);
1440					}
1441				}
1442	
1443				for (auto w : wand_wor_index)
1444				{
1445					bool wand = wand_map.count(w);
1446					SigSpec sigs = wand ? wand_map.at(w) : wor_map.at(w);
1447	
1448					if (GetSize(sigs) == 0)
1449						continue;
1450	
1451					if (GetSize(w) == 1) {
1452						if (wand)
1453							module->addReduceAnd(NEW_ID, sigs, w);
1454						else
1455							module->addReduceOr(NEW_ID, sigs, w);
1456						continue;
1457					}
1458	
1459					SigSpec s = sigs.extract(0, GetSize(w));
1460					for (int i = GetSize(w); i < GetSize(sigs); i += GetSize(w)) {
1461						if (wand)
1462							s = module->And(NEW_ID, s, sigs.extract(i, GetSize(w)));
1463						else
1464							s = module->Or(NEW_ID, s, sigs.extract(i, GetSize(w)));
1465					}
1466					module->connect(w, s);
1467				}
1468	
1469				for (auto cell : module->cells())
1470				{
1471					Module *m = design->module(cell->type);
1472	
1473					if (m == nullptr)
1474						continue;
1475	
1476					bool boxed_params = false;
1477					if (m->get_blackbox_attribute() && !cell->parameters.empty()) {
1478						if (m->get_bool_attribute(ID::dynports)) {
1479							IdString new_m_name = m->derive(design, cell->parameters, true);
1480							if (new_m_name.empty())
1481								continue;
1482							if (new_m_name != m->name) {
1483								m = design->module(new_m_name);
1484								blackbox_derivatives.insert(m);
1485							}
1486						} else {
1487							boxed_params = true;
1488						}
1489					}
1490	
1491					for (auto &conn : cell->connections())
1492					{
1493						Wire *w = m->wire(conn.first);
1494	
1495						if (w == nullptr || w->port_id == 0)
1496							continue;
1497	
1498						if (GetSize(conn.second) == 0)
1499							continue;
1500	
1501						SigSpec sig = conn.second;
1502	
1503						bool resize_widths = !keep_portwidths && GetSize(w) != GetSize(conn.second);
1504						if (resize_widths && verific_mod && boxed_params)
1505							log_debug("Ignoring width mismatch on %s.%s.%s from verific, is port width parametrizable?\n",
1506									module, cell, conn.first.unescape()
1507							);
1508						else if (resize_widths) {
1509							if (GetSize(w) < GetSize(conn.second))
1510							{
1511								int n = GetSize(conn.second) - GetSize(w);
1512								if (!w->port_input && w->port_output)
1513								{
1514									RTLIL::SigSpec out = sig.extract(0, GetSize(w));
1515									out.extend_u0(GetSize(sig), w->is_signed);
1516									module->connect(sig.extract(GetSize(w), n), out.extract(GetSize(w), n));
1517								}
1518								sig.remove(GetSize(w), n);
1519							}
1520							else
1521							{
1522								int n = GetSize(w) - GetSize(conn.second);
1523								if (w->port_input && !w->port_output)
1524									sig.extend_u0(GetSize(w), sig.is_wire() && sig.as_wire()->is_signed);
1525								else
1526									sig.append(module->addWire(NEW_ID, n));
1527							}
1528	
1529							if (!conn.second.is_fully_const() || !w->port_input || w->port_output)
1530								log_warning("Resizing cell port %s.%s.%s from %d bits to %d bits.\n", module, cell,
1531										conn.first.unescape(), GetSize(conn.second), GetSize(sig));
1532							cell->setPort(conn.first, sig);
1533						}
1534	
1535						if (w->port_output && !w->port_input && sig.has_const())
1536							log_error("Output port %s.%s.%s (%s) is connected to constants: %s\n",
1537									module, cell, conn.first.unescape(), cell->type.unescape(), log_signal(sig));
1538					}
1539				}
1540			}
1541	
1542			for (auto module : blackbox_derivatives)
1543				design->remove(module);
1544	
1545			log_pop();
1546		}
1547	} HierarchyPass;
1548	
1549	PRIVATE_NAMESPACE_END
1550

