29	USING_YOSYS_NAMESPACE
30	PRIVATE_NAMESPACE_BEGIN
31	
32	template <typename... Args>
33	[[nodiscard]] std::string concat_views(const Args&... views) {
34	    static_assert((std::is_convertible_v<Args, std::string_view> && ...),
35	                  "All arguments must be convertible to std::string_view.");
36	    const std::size_t total_size = (std::string_view(views).size() + ... + 0);
37	
38	    std::string result;
39	    result.reserve(total_size);
40	
41	    (result.append(views), ...);
42	    return result;
43	}
44	
45	IdString concat_name(RTLIL::Cell *cell, IdString const &object_name, const std::string &separator = ".")
46	{
47		std::string_view object_name_view(object_name.c_str());
48		if (object_name_view[0] == '\\'){
49			return concat_views(cell->name.c_str(), separator, object_name_view.substr(1));
50		}
51	
52		constexpr std::string_view prefix = "$flatten";
53		if (object_name_view.substr(0, prefix.size()) == prefix){
54			object_name_view.remove_prefix(prefix.size());
55		}
56		return concat_views(prefix, cell->name.c_str(), separator, object_name_view);
57	}
58	
59	template<class T>
60	IdString map_name(RTLIL::Cell *cell, T *object, const std::string &separator = ".")
61	{
62		return cell->module->uniquify(concat_name(cell, object->name, separator));
63	}
64	
65	void map_sigspec(const dict<RTLIL::Wire*, RTLIL::Wire*> &map, RTLIL::SigSpec &sig, RTLIL::Module *into = nullptr)
66	{
67		vector<SigChunk> chunks = sig;
68		for (auto &chunk : chunks)
69			if (chunk.wire != nullptr && chunk.wire->module != into)
70				chunk.wire = map.at(chunk.wire);
71		sig = chunks;
72	}
73	
74	struct FlattenWorker
75	{
76		bool ignore_wb = false;
77		bool create_scopeinfo = true;
78		bool create_scopename = false;
79		std::string separator = ".";
80	
81		template<class T>
82		void map_attributes(RTLIL::Cell *cell, T *object, IdString orig_object_name)
83		{
84			if (!create_scopeinfo && object->has_attribute(ID::src))
85				object->add_strpool_attribute(ID::src, cell->get_strpool_attribute(ID::src));
86	
87			// Preserve original names via the hdlname attribute, but only for objects with a fully public name.
88			// If the '-scopename' option is used, also preserve the containing scope of private objects if their scope is fully public.
89			if (cell->name[0] == '\\') {
90				if (object->has_attribute(ID::hdlname) || orig_object_name[0] == '\\') {
91					std::string new_hdlname;
92	
93					if (cell->has_attribute(ID::hdlname)) {
94						new_hdlname = cell->get_string_attribute(ID(hdlname));
95					} else {
96						log_assert(!cell->name.empty());
97						new_hdlname = cell->name.c_str() + 1;
98					}
99					new_hdlname += ' ';
100	
101					if (object->has_attribute(ID::hdlname)) {
102						new_hdlname += object->get_string_attribute(ID(hdlname));
103					} else {
104						log_assert(!orig_object_name.empty());
105						new_hdlname += orig_object_name.c_str() + 1;
106					}
107					object->set_string_attribute(ID(hdlname), new_hdlname);
108				} else if (object->has_attribute(ID(scopename))) {
109					std::string new_scopename;
110	
111					if (cell->has_attribute(ID::hdlname)) {
112						new_scopename = cell->get_string_attribute(ID(hdlname));
113					} else {
114						log_assert(!cell->name.empty());
115						new_scopename = cell->name.c_str() + 1;
116					}
117					new_scopename += ' ';
118					new_scopename += object->get_string_attribute(ID(scopename));
119					object->set_string_attribute(ID(scopename), new_scopename);
120				} else if (create_scopename) {
121					log_assert(!cell->name.empty());
122					object->set_string_attribute(ID(scopename), cell->name.c_str() + 1);
123				}
124			}
125		}
126	
127		void flatten_cell(RTLIL::Design *design, RTLIL::Module *module, RTLIL::Cell *cell, RTLIL::Module *tpl, SigMap &sigmap, std::vector<RTLIL::Cell*> &new_cells, const std::string &separator)
128		{
129			// Copy the contents of the flattened cell
130	
131			dict<IdString, IdString> memory_map;
132			for (auto &tpl_memory_it : tpl->memories) {
133				RTLIL::Memory *new_memory = module->addMemory(map_name(cell, tpl_memory_it.second, separator), tpl_memory_it.second);
134				map_attributes(cell, new_memory, tpl_memory_it.second->name);
135				memory_map[tpl_memory_it.first] = new_memory->name;
136				design->select(module, new_memory);
137			}
138	
139			dict<RTLIL::Wire*, RTLIL::Wire*> wire_map;
140			dict<IdString, IdString> positional_ports;
141			for (auto tpl_wire : tpl->wires()) {
142				if (tpl_wire->port_id > 0)
143					positional_ports.emplace(stringf("$%d", tpl_wire->port_id), tpl_wire->name);
144	
145				RTLIL::Wire *new_wire = nullptr;
146				if (tpl_wire->name[0] == '\\') {
147					RTLIL::Wire *hier_wire = module->wire(concat_name(cell, tpl_wire->name, separator));
148					if (hier_wire != nullptr && hier_wire->get_bool_attribute(ID::hierconn)) {
149						hier_wire->attributes.erase(ID::hierconn);
150						if (GetSize(hier_wire) < GetSize(tpl_wire)) {
151							log_warning("Widening signal %s.%s to match size of %s.%s (via %s.%s).\n",
152								module, hier_wire, tpl, tpl_wire, module, cell);
153							hier_wire->width = GetSize(tpl_wire);
154						}
155						new_wire = hier_wire;
156					}
157				}
158				if (new_wire == nullptr) {
159					new_wire = module->addWire(map_name(cell, tpl_wire, separator), tpl_wire);
160					new_wire->port_input = new_wire->port_output = false;
161					new_wire->port_id = false;
162				}
163	
164				map_attributes(cell, new_wire, tpl_wire->name);
165				wire_map[tpl_wire] = new_wire;
166				design->select(module, new_wire);
167			}
168	
169			for (auto &tpl_proc_it : tpl->processes) {
170				RTLIL::Process *new_proc = module->addProcess(map_name(cell, tpl_proc_it.second, separator), tpl_proc_it.second);
171				map_attributes(cell, new_proc, tpl_proc_it.second->name);
172				for (auto new_proc_sync : new_proc->syncs)
173					for (auto &memwr_action : new_proc_sync->mem_write_actions)
174						memwr_action.memid = memory_map.at(memwr_action.memid).str();
175				auto rewriter = [&](RTLIL::SigSpec &sig) { map_sigspec(wire_map, sig); };
176				new_proc->rewrite_sigspecs(rewriter);
177				design->select(module, new_proc);
178			}
179	
180			for (auto tpl_cell : tpl->cells()) {
181				RTLIL::Cell *new_cell = module->addCell(map_name(cell, tpl_cell, separator), tpl_cell);
182				map_attributes(cell, new_cell, tpl_cell->name);
183				if (new_cell->has_memid()) {
184					IdString memid = new_cell->getParam(ID::MEMID).decode_string();
185					new_cell->setParam(ID::MEMID, Const(memory_map.at(memid).str()));
186				} else if (new_cell->is_mem_cell()) {
187					IdString memid = new_cell->getParam(ID::MEMID).decode_string();
188					new_cell->setParam(ID::MEMID, Const(concat_name(cell, memid, separator).str()));
189				}
190				auto rewriter = [&](RTLIL::SigSpec &sig) { map_sigspec(wire_map, sig); };
191				new_cell->rewrite_sigspecs(rewriter);
192				design->select(module, new_cell);
193				new_cells.push_back(new_cell);
194			}
195	
196			for (auto &tpl_conn_it : tpl->connections()) {
197				RTLIL::SigSig new_conn = tpl_conn_it;
198				map_sigspec(wire_map, new_conn.first);
199				map_sigspec(wire_map, new_conn.second);
200				module->connect(new_conn);
201			}
202	
203			// Attach port connections of the flattened cell
204	
205			pool<SigBit> tpl_driven;
206			for (auto tpl_cell : tpl->cells())
207				for (auto &tpl_conn : tpl_cell->connections())
208					if (tpl_cell->output(tpl_conn.first))
209						for (auto bit : tpl_conn.second)
210							tpl_driven.insert(bit);
211			for (auto &tpl_conn : tpl->connections())
212				for (auto bit : tpl_conn.first)
213					tpl_driven.insert(bit);
214	
215			for (auto &port_it : cell->connections())
216			{
217				IdString port_name = port_it.first;
218				if (positional_ports.count(port_name) > 0)
219					port_name = positional_ports.at(port_name);
220				if (tpl->wire(port_name) == nullptr || tpl->wire(port_name)->port_id == 0) {
221					if (port_name.begins_with("$"))
222						log_error("Can't map port `%s' of cell `%s' to template `%s'!\n",
223							port_name.c_str(), cell->name.c_str(), tpl->name.c_str());
224					continue;
225				}
226	
227				if (GetSize(port_it.second) == 0)
228					continue;
229	
230				RTLIL::Wire *tpl_wire = tpl->wire(port_name);
231				RTLIL::SigSig new_conn;
232				bool is_signed = false;
233				if (tpl_wire->port_output && !tpl_wire->port_input) {
234					new_conn.first = port_it.second;
235					new_conn.second = tpl_wire;
236					is_signed = tpl_wire->is_signed;
237				} else if (!tpl_wire->port_output && tpl_wire->port_input) {
238					new_conn.first = tpl_wire;
239					new_conn.second = port_it.second;
240					is_signed = new_conn.second.is_wire() && new_conn.second.as_wire()->is_signed;
241				} else {
242					SigSpec sig_tpl = tpl_wire, sig_mod = port_it.second;
243					for (int i = 0; i < GetSize(sig_tpl) && i < GetSize(sig_mod); i++) {
244						if (tpl_driven.count(sig_tpl[i])) {
245							new_conn.first.append(sig_mod[i]);
246							new_conn.second.append(sig_tpl[i]);
247						} else {
248							new_conn.first.append(sig_tpl[i]);
249							new_conn.second.append(sig_mod[i]);
250						}
251					}
252				}
253				map_sigspec(wire_map, new_conn.first, module);
254				map_sigspec(wire_map, new_conn.second, module);
255	
256				if (new_conn.second.size() > new_conn.first.size())
257					new_conn.second.remove(new_conn.first.size(), new_conn.second.size() - new_conn.first.size());
258				if (new_conn.second.size() < new_conn.first.size())
259					new_conn.second.extend_u0(new_conn.first.size(), is_signed);
260				log_assert(new_conn.first.size() == new_conn.second.size());
261	
262				if (sigmap(new_conn.first).has_const())
263					log_error("Cell port %s.%s.%s is driving constant bits: %s <= %s\n",
264						module, cell, port_it.first.unescape(), log_signal(new_conn.first), log_signal(new_conn.second));
265	
266				module->connect(new_conn);
267				sigmap.add(new_conn.first, new_conn.second);
268			}
269	
270			RTLIL::Cell *scopeinfo = nullptr;
271			RTLIL::IdString cell_name = cell->name;
272	
273			if (create_scopeinfo && cell_name.isPublic())
274			{
275				// The $scopeinfo's name will be changed below after removing the flattened cell
276				scopeinfo = module->addCell(NEW_ID, ID($scopeinfo));
277				scopeinfo->setParam(ID::TYPE, RTLIL::Const("module"));
278	
279				for (auto const &attr : cell->attributes)
280				{
281					if (attr.first == ID::hdlname)
282						scopeinfo->attributes.insert(attr);
283					else
284						scopeinfo->attributes.emplace(stringf("\\cell_%s", attr.first.unescape()), attr.second);
285				}
286	
287				for (auto const &attr : tpl->attributes)
288					scopeinfo->attributes.emplace(stringf("\\module_%s", attr.first.unescape()), attr.second);
289	
290				scopeinfo->attributes.emplace(ID(module), tpl->name.unescape());
291			}
292	
293			module->remove(cell);
294	
295			if (scopeinfo != nullptr)
296				module->rename(scopeinfo, cell_name);
297		}
298	
299		void flatten_module(RTLIL::Design *design, RTLIL::Module *module, pool<RTLIL::Module*> &used_modules, const std::string &separator)
300		{
301			if (!design->selected(module) || module->get_blackbox_attribute(ignore_wb))
302				return;
303	
304			SigMap sigmap(module);
305			std::vector<RTLIL::Cell*> worklist = module->selected_cells();
306			while (!worklist.empty())
307			{
308				RTLIL::Cell *cell = worklist.back();
309				worklist.pop_back();
310	
311				if (!design->has(cell->type))
312					continue;
313	
314				RTLIL::Module *tpl = design->module(cell->type);
315				if (tpl->get_blackbox_attribute(ignore_wb))
316					continue;
317	
318				if (cell->get_bool_attribute(ID::keep_hierarchy) || tpl->get_bool_attribute(ID::keep_hierarchy)) {
319					log("Keeping %s.%s (found keep_hierarchy attribute).\n", module, cell);
320					used_modules.insert(tpl);
321					continue;
322				}
323	
324				log_debug("Flattening %s.%s (%s).\n", module, cell, cell->type.unescape());
325				// If a design is fully selected and has a top module defined, topological sorting ensures that all cells
326				// added during flattening are black boxes, and flattening is finished in one pass. However, when flattening
327				// individual modules, this isn't the case, and the newly added cells might have to be flattened further.
328				flatten_cell(design, module, cell, tpl, sigmap, worklist, separator);
329			}
330		}
331	};
332	
333	struct FlattenPass : public Pass {
334		FlattenPass() : Pass("flatten", "flatten design") { }
335		void help() override
336		{
337			//   |---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|
338			log("\n");
339			log("    flatten [options] [selection]\n");
340			log("\n");
341			log("This pass flattens the design by replacing cells by their implementation. This\n");
342			log("pass is very similar to the 'techmap' pass. The only difference is that this\n");
343			log("pass is using the current design as mapping library.\n");
344			log("\n");
345			log("Cells and/or modules with the 'keep_hierarchy' attribute set will not be\n");
346			log("flattened by this command.\n");
347			log("\n");
348			log("    -wb\n");
349			log("        Ignore the 'whitebox' attribute on cell implementations.\n");
350			log("\n");
351			log("    -noscopeinfo\n");
352			log("        Do not create '$scopeinfo' cells that preserve attributes of cells and\n");
353			log("        modules that were removed during flattening. With this option, the\n");
354			log("        'src' attribute of a given cell is merged into all objects replacing\n");
355			log("        that cell, with multiple distinct 'src' locations separated by '|'.\n");
356			log("        Without this option these 'src' locations can be found via the\n");
357			log("        cell_src' and 'module_src' attribute of '$scopeinfo' cells.\n");
358			log("\n");
359			log("    -scopename\n");
360			log("        Create 'scopename' attributes for objects with a private name. This\n");
361			log("        attribute records the 'hdlname' of the enclosing scope. For objects\n");
362			log("        with a public name the enclosing scope can be found via their\n");
363			log("        'hdlname' attribute.\n");
364			log("\n");
365			log("    -separator <char>\n");
366			log("        Use this separator char instead of '.' when concatenating design levels.\n");
367			log("\n");
368			log("    -nocleanup\n");
369			log("        Don't remove unused submodules, leave a flattened version of each\n");
370			log("        submodule in the design.\n");
371			log("\n");
372		}
373		void execute(std::vector<std::string> args, RTLIL::Design *design) override
374		{
375			log_header(design, "Executing FLATTEN pass (flatten design).\n");
376			log_push();
377	
378			FlattenWorker worker;
379	
380			if (design->scratchpad.count("flatten.separator"))
381				worker.separator = design->scratchpad_get_string("flatten.separator");
382	
383			bool cleanup = true;
384	
385			size_t argidx;
386			for (argidx = 1; argidx < args.size(); argidx++) {
387				if (args[argidx] == "-wb") {
388					worker.ignore_wb = true;
389					continue;
390				}
391				if (args[argidx] == "-noscopeinfo") {
392					worker.create_scopeinfo = false;
393					continue;
394				}
395				if (args[argidx] == "-scopename") {
396					worker.create_scopename = true;
397					continue;
398				}
399				if (args[argidx] == "-separator" && argidx + 1 < args.size()) {
400					worker.separator = args[++argidx];
401					continue;
402				}
403				if (args[argidx] == "-nocleanup") {
404					cleanup = false;
405					continue;
406				}
407				break;
408			}
409			extra_args(args, argidx, design);
410	
411			RTLIL::Module *top = nullptr;
412			if (design->full_selection())
413				for (auto module : design->modules())
414					if (module->get_bool_attribute(ID::top))
415						top = module;
416	
417			pool<RTLIL::Module*> used_modules;
418			if (top == nullptr)
419				used_modules = design->modules();
420			else
421				used_modules.insert(top);
422	
423			TopoSort<RTLIL::Module*, IdString::compare_ptr_by_name<RTLIL::Module>> topo_modules;
424			pool<RTLIL::Module*> worklist = used_modules;
425			while (!worklist.empty()) {
426				RTLIL::Module *module = worklist.pop();
427				for (auto cell : module->selected_cells()) {
428					RTLIL::Module *tpl = design->module(cell->type);
429					if (tpl != nullptr) {
430	                                        if (!topo_modules.has_node(tpl))
431							worklist.insert(tpl);
432						topo_modules.edge(tpl, module);
433					}
434				}
435			}
436	
437			if (!topo_modules.sort())
438				log_error("Cannot flatten a design containing recursive instantiations.\n");
439	
440			for (auto module : topo_modules.sorted)
441				worker.flatten_module(design, module, used_modules, worker.separator);
442	
443			if (cleanup && top != nullptr)
444				for (auto module : design->modules().to_vector())
445					if (!used_modules[module] && !module->get_blackbox_attribute(worker.ignore_wb)) {
446						log("Deleting now unused module %s.\n", module);
447						design->remove(module);
448					}
