9	 *
10	 *  THE SOFTWARE IS PROVIDED "AS IS" AND THE AUTHOR DISCLAIMS ALL WARRANTIES
11	 *  WITH REGARD TO THIS SOFTWARE INCLUDING ALL IMPLIED WARRANTIES OF
12	 *  MERCHANTABILITY AND FITNESS. IN NO EVENT SHALL THE AUTHOR BE LIABLE FOR
13	 *  ANY SPECIAL, DIRECT, INDIRECT, OR CONSEQUENTIAL DAMAGES OR ANY DAMAGES
14	 *  WHATSOEVER RESULTING FROM LOSS OF USE, DATA OR PROFITS, WHETHER IN AN
15	 *  ACTION OF CONTRACT, NEGLIGENCE OR OTHER TORTIOUS ACTION, ARISING OUT OF
16	 *  OR IN CONNECTION WITH THE USE OR PERFORMANCE OF THIS SOFTWARE.
17	 *
18	 */
19	
20	#include "kernel/register.h"
21	#include "kernel/celltypes.h"
22	#include "kernel/log.h"
23	#include "kernel/sigtools.h"
24	#include <stdlib.h>
25	#include <stdio.h>
26	#include <set>
27	
28	USING_YOSYS_NAMESPACE
29	PRIVATE_NAMESPACE_BEGIN
30	
31	struct SubmodWorker
32	{
33		CellTypes ct;
34		RTLIL::Design *design;
35		RTLIL::Module *module;
36		SigMap sigmap;
37	
38		bool copy_mode;
39		bool hidden_mode;
40		std::string opt_name;
41	
42		struct SubModule
43		{
44			std::string name, full_name;
45			pool<RTLIL::Cell*> cells;
46		};
47	
48		std::map<std::string, SubModule> submodules;
49	
50		struct wire_flags_t {
51			RTLIL::Wire *new_wire;
52			RTLIL::Const is_int_driven;
53			bool is_int_used, is_ext_driven, is_ext_used;
54			wire_flags_t(RTLIL::Wire* wire) : new_wire(nullptr), is_int_driven(State::S0, GetSize(wire)), is_int_used(false), is_ext_driven(false), is_ext_used(false) { }
55		};
56		std::map<RTLIL::Wire*, wire_flags_t> wire_flags;
57		bool flag_found_something;
58	
59		void flag_wire(RTLIL::Wire *wire, bool create, bool set_int_used, bool set_ext_driven, bool set_ext_used)
60		{
61			if (wire_flags.count(wire) == 0) {
62				if (!create)
63					return;
64				wire_flags.emplace(wire, wire);
65			}
66			if (set_int_used)
67				wire_flags.at(wire).is_int_used = true;
68			if (set_ext_driven)
69				wire_flags.at(wire).is_ext_driven = true;
70			if (set_ext_used)
71				wire_flags.at(wire).is_ext_used = true;
72			flag_found_something = true;
73		}
74	
75		void flag_signal(const RTLIL::SigSpec &sig, bool create, bool set_int_driven, bool set_int_used, bool set_ext_driven, bool set_ext_used)
76		{
77			for (auto &c : sig.chunks())
78				if (c.wire != nullptr) {
79					flag_wire(c.wire, create, set_int_used, set_ext_driven, set_ext_used);
80					if (set_int_driven)
81						for (int i = c.offset; i < c.offset+c.width; i++) {
82							wire_flags.at(c.wire).is_int_driven.set(i, State::S1);
83							flag_found_something = true;
84						}
85				}
86		}
87	
88		void handle_submodule(SubModule &submod)
89		{
90			log("Creating submodule %s (%s) of module %s.\n", submod.name, submod.full_name, module->name);
91	
92			wire_flags.clear();
93			for (RTLIL::Cell *cell : submod.cells) {
94				if (ct.cell_known(cell->type)) {
95					for (auto &conn : cell->connections())
96						flag_signal(conn.second, true, ct.cell_output(cell->type, conn.first), ct.cell_input(cell->type, conn.first), false, false);
97				} else {
98					log_warning("Port directions for cell %s (%s) are unknown. Assuming inout for all ports.\n", cell->name, cell->type);
99					for (auto &conn : cell->connections())
100						flag_signal(conn.second, true, true, true, false, false);
101				}
102			}
103			for (auto cell : module->cells()) {
104				if (submod.cells.count(cell) > 0)
105					continue;
106				if (ct.cell_known(cell->type)) {
107					for (auto &conn : cell->connections())
108						flag_signal(conn.second, false, false, false, ct.cell_output(cell->type, conn.first), ct.cell_input(cell->type, conn.first));
109				} else {
110					flag_found_something = false;
111					for (auto &conn : cell->connections())
112						flag_signal(conn.second, false, false, false, true, true);
113					if (flag_found_something)
114						log_warning("Port directions for cell %s (%s) are unknown. Assuming inout for all ports.\n", cell->name, cell->type);
115				}
116			}
117	
118			RTLIL::Module *new_mod = new RTLIL::Module;
119			new_mod->name = submod.full_name;
120			design->add(new_mod);
121			int auto_name_counter = 1;
122	
123			std::set<RTLIL::IdString> all_wire_names;
124			for (auto &it : wire_flags) {
125				all_wire_names.insert(it.first->name);
126			}
127	
128			for (auto &it : wire_flags)
129			{
130				RTLIL::Wire *wire = it.first;
131				wire_flags_t &flags = it.second;
132	
133				if (wire->port_input)
134					flags.is_ext_driven = true;
135				if (wire->port_output)
136					flags.is_ext_used = true;
137				else {
138					auto sig = sigmap(wire);
139					for (auto c : sig.chunks())
140						if (c.wire && c.wire->port_output) {
141							flags.is_ext_used = true;
142							break;
143						}
144				}
145	
146				bool new_wire_port_input = false;
147				bool new_wire_port_output = false;
148	
149				if (!flags.is_int_driven.is_fully_zero() && flags.is_ext_used)
150					new_wire_port_output = true;
151				if (flags.is_ext_driven && flags.is_int_used)
152					new_wire_port_input = true;
153	
154				if (!flags.is_int_driven.is_fully_zero() && flags.is_ext_driven)
155					new_wire_port_input = true, new_wire_port_output = true;
156	
157				std::string new_wire_name = wire->name.str();
158				if (new_wire_port_input || new_wire_port_output) {
159					if (new_wire_name[0] == '$')
160						while (1) {
161							std::string next_wire_name = stringf("%s\\n%d", hidden_mode ? "$submod" : "", auto_name_counter++);
162							if (all_wire_names.count(next_wire_name) == 0) {
163								all_wire_names.insert(next_wire_name);
164								new_wire_name = next_wire_name;
165								break;
166							}
167						}
168					else if (hidden_mode)
169						new_wire_name = stringf("$submod%s", new_wire_name);
170				}
171	
172				RTLIL::Wire *new_wire = new_mod->addWire(new_wire_name, wire->width);
173				new_wire->port_input = new_wire_port_input;
174				new_wire->port_output = new_wire_port_output;
175				new_wire->start_offset = wire->start_offset;
176				new_wire->attributes = wire->attributes;
177				if (!flags.is_int_driven.is_fully_zero()) {
178					new_wire->attributes.erase(ID::init);
179					auto sig = sigmap(wire);
180					for (int i = 0; i < GetSize(sig); i++) {
181						if (flags.is_int_driven[i] == State::S0)
182							continue;
183						if (!sig[i].wire)
184							continue;
185						auto it = sig[i].wire->attributes.find(ID::init);
186						if (it != sig[i].wire->attributes.end()) {
187							auto jt = new_wire->attributes.insert(std::make_pair(ID::init, Const(State::Sx, GetSize(sig)))).first;
188							jt->second.set(i, it->second[sig[i].offset]);
189							it->second.set(sig[i].offset, State::Sx);
190						}
191					}
192				}
193	
194				if (new_wire->port_input && new_wire->port_output)
195					log("  signal %s: inout %s\n", wire->name, new_wire->name);
196				else if (new_wire->port_input)
197					log("  signal %s: input %s\n", wire->name, new_wire->name);
198				else if (new_wire->port_output)
199					log("  signal %s: output %s\n", wire->name, new_wire->name);
200				else
201					log("  signal %s: internal\n", wire->name);
202	
203				flags.new_wire = new_wire;
204			}
205	
206			new_mod->fixup_ports();
207			ct.setup_module(new_mod);
208	
209			for (RTLIL::Cell *cell : submod.cells) {
210				RTLIL::Cell *new_cell = new_mod->addCell(cell->name, cell);
211				for (auto &conn : new_cell->connections_)
212					for (auto &bit : conn.second)
213						if (bit.wire != nullptr) {
214							log_assert(wire_flags.count(bit.wire) > 0);
215							bit.wire = wire_flags.at(bit.wire).new_wire;
216						}
217				log("  cell %s (%s)\n", new_cell->name, new_cell->type);
218				if (!copy_mode)
219					module->remove(cell);
220			}
221			submod.cells.clear();
222	
223			if (!copy_mode) {
224				RTLIL::Cell *new_cell = module->addCell(submod.full_name, submod.full_name);
225				for (auto &it : wire_flags)
226				{
227					RTLIL::SigSpec old_sig = sigmap(it.first);
228					RTLIL::Wire *new_wire = it.second.new_wire;
229					if (new_wire->port_id > 0) {
230						if (new_wire->port_output)
231							for (int i = 0; i < GetSize(old_sig); i++) {
232								auto &b = old_sig[i];
233								// Prevents "ERROR: Mismatch in directionality ..." when flattening
234								if (!b.wire)
235									b = module->addWire(NEW_ID);
236								// Prevents "Warning: multiple conflicting drivers ..."
237								else if (!it.second.is_int_driven[i])
238									b = module->addWire(NEW_ID);
239							}
240						new_cell->setPort(new_wire->name, old_sig);
241					}
242				}
243			}
244		}
245	
246		SubmodWorker(RTLIL::Design *design, RTLIL::Module *module, bool copy_mode = false, bool hidden_mode = false, std::string opt_name = std::string()) :
247				design(design), module(module), sigmap(module), copy_mode(copy_mode), hidden_mode(hidden_mode), opt_name(opt_name)
248		{
249			if (!module->is_selected_whole() && opt_name.empty())
250				return;
251	
252			if (module->processes.size() > 0) {
253				log("Skipping module %s as it contains processes (run 'proc' pass first).\n", module->name);
254				return;
255			}
256	
257			if (module->memories.size() > 0) {
258				log("Skipping module %s as it contains memories (run 'memory' pass first).\n", module->name);
259				return;
260			}
261	
262			ct.setup_internals();
263			ct.setup_internals_anyinit();
264			ct.setup_internals_mem();
265			ct.setup_stdcells();
266			ct.setup_stdcells_mem();
267			ct.setup_design(design);
268	
269			for (auto port : module->ports) {
270				auto wire = module->wire(port);
271				if (wire->port_output)
272					sigmap.add(wire);
273			}
274	
275			if (opt_name.empty())
276			{
277				for (auto wire : module->wires())
278					wire->attributes.erase(ID::submod);
279	
280				for (auto cell : module->cells())
281				{
282					if (cell->attributes.count(ID::submod) == 0 || cell->attributes[ID::submod].size() == 0) {
283						cell->attributes.erase(ID::submod);
284						continue;
285					}
286	
287					std::string submod_str = cell->attributes[ID::submod].decode_string();
288					cell->attributes.erase(ID::submod);
289	
290					if (submodules.count(submod_str) == 0) {
291						submodules[submod_str].name = submod_str;
292						submodules[submod_str].full_name = module->name.str() + "_" + submod_str;
293						while (design->module(submodules[submod_str].full_name) != nullptr ||
294								module->count_id(submodules[submod_str].full_name) != 0)
295							submodules[submod_str].full_name += "_";
296					}
297	
298					submodules[submod_str].cells.insert(cell);
299				}
300			}
301			else
302			{
303				for (auto cell : module->cells())
304				{
305					if (!design->selected(module, cell))
306						continue;
307					submodules[opt_name].name = opt_name;
308					submodules[opt_name].full_name = RTLIL::escape_id(opt_name);
309					submodules[opt_name].cells.insert(cell);
310				}
311	
312				if (submodules.size() == 0)
313					log("Nothing selected -> do nothing.\n");
314			}
315	
316			for (auto &it : submodules)
317				handle_submodule(it.second);
318		}
319	};
320	
321	struct SubmodPass : public Pass {
322		SubmodPass() : Pass("submod", "moving part of a module to a new submodule") { }
323		void help() override
324		{
325			//   |---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|
326			log("\n");
327			log("    submod [options] [selection]\n");
328			log("\n");
329			log("This pass identifies all cells with the 'submod' attribute and moves them to\n");
330			log("a newly created module. The value of the attribute is used as name for the\n");
331			log("cell that replaces the group of cells with the same attribute value.\n");
332			log("\n");
333			log("This pass can be used to create a design hierarchy in flat design. This can\n");
334			log("be useful for analyzing or reverse-engineering a design.\n");
335			log("\n");
336			log("This pass only operates on completely selected modules with no processes\n");
337			log("or memories.\n");
338			log("\n");
339			log("    -copy\n");
340			log("        by default the cells are 'moved' from the source module and the source\n");
341			log("        module will use an instance of the new module after this command is\n");
342			log("        finished. call with -copy to not modify the source module.\n");
343			log("\n");
344			log("    -name <name>\n");
345			log("        don't use the 'submod' attribute but instead use the selection. only\n");
346			log("        objects from one module might be selected. the value of the -name option\n");
347			log("        is used as the value of the 'submod' attribute instead.\n");
348			log("\n");
349			log("    -hidden\n");
350			log("        instead of creating submodule ports with public names, create ports with\n");
351			log("        private names so that a subsequent 'flatten; clean' call will restore\n");
352			log("        the original module with original public names.\n");
353			log("\n");
354		}
355		void execute(std::vector<std::string> args, RTLIL::Design *design) override
356		{
357			log_header(design, "Executing SUBMOD pass (moving cells to submodules as requested).\n");
358			log_push();
359	
360			std::string opt_name;
361			bool copy_mode = false;
362			bool hidden_mode = false;
363	
364			size_t argidx;
365			for (argidx = 1; argidx < args.size(); argidx++) {
366				if (args[argidx] == "-name" && argidx+1 < args.size()) {
367					opt_name = args[++argidx];
368					continue;
369				}
370				if (args[argidx] == "-copy") {
371					copy_mode = true;
372					continue;
373				}
374				if (args[argidx] == "-hidden") {
375					hidden_mode = true;
376					continue;
377				}
378				break;
379			}
380			extra_args(args, argidx, design);
381	
382			if (opt_name.empty())
383			{
384				Pass::call(design, "opt_clean");
385				log_header(design, "Continuing SUBMOD pass.\n");
386	
387				std::set<RTLIL::IdString> handled_modules;
388	
389				bool did_something = true;
390				while (did_something) {
391					did_something = false;
392					std::vector<RTLIL::IdString> queued_modules;
393					for (auto mod : design->modules())
394						if (handled_modules.count(mod->name) == 0 && design->selected_whole_module(mod->name))
395							queued_modules.push_back(mod->name);
396					for (auto &modname : queued_modules)
397						if (design->module(modname) != nullptr) {
398							SubmodWorker worker(design, design->module(modname), copy_mode, hidden_mode);
399							handled_modules.insert(modname);
400							did_something = true;
401						}
402				}
403	
404				Pass::call(design, "opt_clean");
405			}
406			else
407			{
408				RTLIL::Module *module = nullptr;
409				for (auto mod : design->selected_modules()) {
410					if (module != nullptr)
411						log_cmd_error("More than one module selected: %s %s\n", module->name, mod->name);
412					module = mod;
413				}
414				if (module == nullptr)
415					log("Nothing selected -> do nothing.\n");
416				else {
417					Pass::call_on_module(design, module, "opt_clean");
418					log_header(design, "Continuing SUBMOD pass.\n");
419					SubmodWorker worker(design, module, copy_mode, hidden_mode, opt_name);
420				}
421			}
422	
423			log_pop();
424		}
425	} SubmodPass;
426	
427	PRIVATE_NAMESPACE_END
