	if (!design->has(modname) && new_ast) {
		new_ast->str = modname;
		process_module(design, new_ast.get(), false, NULL, quiet);
		design->module(modname)->check();
	} else if (!quiet) {
		log("Found cached RTLIL representation for module `%s'.\n", modname);
	}

